import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleInitialize = (e) => {
    e.preventDefault();
    setLoading(true);
    // Simulate a secure handshake/scan before entering
    setTimeout(() => {
      navigate('/dashboard');
    }, 2000);
  };

  return (
    <div style={styles.container}>
      {/* Background Glow Effect */}
      <div style={styles.glow}></div>

      <div style={styles.loginCard}>
        <div style={styles.iconContainer}>
          <div style={styles.shieldIcon}>🛡️</div>
          <div style={styles.pulseRing}></div>
        </div>

        <h1 style={styles.title}>CortexShield AI</h1>
        <p style={styles.subtitle}>Autonomous Defense Node | V 3.2</p>

        <form onSubmit={handleInitialize} style={styles.form}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>ANALYST IDENTIFIER</label>
            <input 
              type="text" 
              placeholder="admin" 
              style={styles.input} 
              required 
            />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>SECURITY PASSKEY</label>
            <input 
              type="password" 
              placeholder="••••••••" 
              style={styles.input} 
              required 
            />
          </div>

          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? "ESTABLISHING SECURE LINK..." : "INITIALIZE SOC"}
          </button>
        </form>

        <div style={styles.footerText}>
          System Status: <span style={{ color: '#00ff9d' }}>Ready</span> | Encryption: <span style={{ color: '#00ff9d' }}>AES-256</span>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    backgroundColor: '#05080a',
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    fontFamily: '"Share Tech Mono", monospace',
    overflow: 'hidden',
    position: 'relative',
  },
  glow: {
    position: 'absolute',
    width: '400px',
    height: '400px',
    background: 'radial-gradient(circle, rgba(0, 255, 157, 0.1) 0%, rgba(0,0,0,0) 70%)',
    zIndex: 0,
  },
  loginCard: {
    backgroundColor: 'rgba(15, 23, 42, 0.8)',
    backdropFilter: 'blur(10px)',
    padding: '40px',
    borderRadius: '15px',
    border: '1px solid rgba(0, 255, 157, 0.3)',
    width: '400px',
    textAlign: 'center',
    zIndex: 1,
    boxShadow: '0 0 30px rgba(0, 0, 0, 0.5)',
  },
  iconContainer: {
    position: 'relative',
    marginBottom: '20px',
    display: 'inline-block',
  },
  shieldIcon: {
    fontSize: '50px',
    zIndex: 2,
    position: 'relative',
  },
  pulseRing: {
    position: 'absolute',
    top: '-10px',
    left: '-10px',
    width: '70px',
    height: '70px',
    border: '2px solid #00ff9d',
    borderRadius: '50%',
    animation: 'pulse 2s infinite',
  },
  title: {
    color: '#00ff9d',
    fontSize: '28px',
    letterSpacing: '3px',
    margin: '10px 0',
    textTransform: 'uppercase',
  },
  subtitle: {
    color: '#94a3b8',
    fontSize: '12px',
    marginBottom: '30px',
    letterSpacing: '1px',
  },
  form: {
    textAlign: 'left',
  },
  inputGroup: {
    marginBottom: '20px',
  },
  label: {
    color: '#64748b',
    fontSize: '10px',
    display: 'block',
    marginBottom: '5px',
    fontWeight: 'bold',
  },
  input: {
    width: '100%',
    padding: '12px',
    backgroundColor: '#0f172a',
    border: '1px solid #1e293b',
    borderRadius: '5px',
    color: '#fff',
    fontSize: '14px',
    outline: 'none',
    boxSizing: 'border-box',
    transition: 'border 0.3s',
  },
  button: {
    width: '100%',
    padding: '15px',
    backgroundColor: '#00ff9d',
    border: 'none',
    borderRadius: '5px',
    color: '#05080a',
    fontWeight: 'bold',
    fontSize: '14px',
    cursor: 'pointer',
    marginTop: '10px',
    transition: '0.3s',
    boxShadow: '0 0 15px rgba(0, 255, 157, 0.4)',
  },
  footerText: {
    marginTop: '25px',
    color: '#475569',
    fontSize: '10px',
  },
};

// Add this animation to your index.css or a style tag in App.js
const styleTag = document.createElement("style");
styleTag.innerHTML = `
  @keyframes pulse {
    0% { transform: scale(0.95); opacity: 0.7; }
    70% { transform: scale(1.1); opacity: 0; }
    100% { transform: scale(0.95); opacity: 0; }
  }
`;
document.head.appendChild(styleTag);

export default LoginPage;
